import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// Knowledge base about Roy
const ROY_KNOWLEDGE = {
  personal: {
    name: "Roy Dinh",
    education: "Computer Science student",
    interests: [
      "Software Engineering",
      "Artificial Intelligence",
      "Web Development",
      "Problem Solving"
    ],
    skills: {
      languages: ["Python", "JavaScript", "Java", "C++", "C", "SQL", "x86-64 Assembly", "HTML/CSS"],
      frontend: ["React"],
      backend: ["Node.js", "Express.js", "Flask"],
      databases: ["PostgreSQL"],
      tools: ["Git", "Docker", "VS Code", "Jupyter Notebook"]
    },
    projects: [
      "Portfolio website with AI integration",
      "Various web development projects",
      "AI and machine learning experiments"
    ]
  }
};

// Basic Computer Science Knowledge
const CS_KNOWLEDGE = {
  dataStructures: {
    arrays: "Linear data structure that stores elements at contiguous memory locations.",
    linkedLists: "Linear data structure where elements are stored in nodes, and each node points to the next node.",
    stacks: "LIFO (Last In First Out) data structure.",
    queues: "FIFO (First In First Out) data structure.",
    trees: "Hierarchical data structure with a root node and child nodes.",
    graphs: "Non-linear data structure consisting of nodes and edges."
  },
  algorithms: {
    sorting: ["Bubble Sort", "Quick Sort", "Merge Sort", "Insertion Sort"],
    searching: ["Linear Search", "Binary Search"],
    complexity: {
      "O(1)": "Constant time",
      "O(log n)": "Logarithmic time",
      "O(n)": "Linear time",
      "O(n log n)": "Linearithmic time",
      "O(n²)": "Quadratic time"
    }
  },
  concepts: {
    oop: "Object-Oriented Programming principles: Encapsulation, Inheritance, Polymorphism, Abstraction",
    databases: "SQL vs NoSQL, ACID properties, Normalization",
    networking: "TCP/IP, HTTP/HTTPS, DNS, REST APIs",
    security: "Authentication, Authorization, Encryption, Hashing"
  }
};

const RoyAI = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      text: "Hi! I'm RoyAI, a digital version of Roy. I can tell you about Roy's skills, experience, and interests. I also know basic computer science concepts and can do simple math. What would you like to know?",
      sender: 'ai'
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    // Add user message
    const userMessage = { text: input, sender: 'user' };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await fetch('http://localhost:3001/api/chat', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ message: input })
      });

      if (!response.ok) {
        throw new Error('Failed to get response');
      }

      const data = await response.json();
      setMessages(prev => [...prev, { text: data.response, sender: 'ai' }]);
    } catch (error) {
      console.error('Error:', error);
      setMessages(prev => [...prev, { 
        text: "I'm sorry, I'm having trouble connecting right now. Please try again later.", 
        sender: 'ai' 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <motion.button
        className="roy-ai-button"
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        {isOpen ? 'Close RoyAI' : 'Chat with RoyAI'}
      </motion.button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="chat-window"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            transition={{ duration: 0.3 }}
          >
            <div className="chat-messages">
              {messages.map((message, index) => (
                <motion.div
                  key={index}
                  className={`message ${message.sender}`}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  {message.text}
                </motion.div>
              ))}
              {isLoading && (
                <motion.div
                  className="message ai"
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                >
                  Thinking...
                </motion.div>
              )}
              <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask me anything..."
                className="chat-input"
                disabled={isLoading}
              />
              <button 
                type="submit" 
                className="send-button"
                disabled={isLoading}
              >
                Send
              </button>
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default RoyAI;
